import sys
import json
import argparse
from dataclasses import dataclass, field, asdict
from typing import Optional, List, Dict, Any, Tuple
from enum import Enum
import lark

VERSION = "0.1.0"

# =============================================================================
# Error Classes
# =============================================================================

class CircuitError(Exception):
    """Base error for circuit-related errors."""
    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message)
        self.message = message
        self.file = file
        self.line = line
        self.col = col


class CliUsageError(CircuitError):
    exit_code = 1


class FileNotFoundError(CircuitError):
    exit_code = 1

    def __init__(self, message: str, filepath: str):
        super().__init__(message, file=filepath)


class CircParseError(CircuitError):
    exit_code = 2


class DeclarationAfterAssignmentError(CircuitError):
    exit_code = 3


class DuplicateNameError(CircuitError):
    exit_code = 3


class UndefinedNameError(CircuitError):
    exit_code = 3


class UnassignedSignalError(CircuitError):
    exit_code = 3


class InputAssignmentError(CircuitError):
    exit_code = 3


class MultipleAssignmentError(CircuitError):
    exit_code = 3


class ArityError(CircuitError):
    exit_code = 3


class CycleError(CircuitError):
    exit_code = 3


# =============================================================================
# Parser using Lark
# =============================================================================

 Circ_GRAMMAR = r"""
    // Comments and whitespace handled by transformer
    ?start: line*

    // Declaration lines
    ?line: declaration | assignment | comment_line | blank_line

    declaration: (INPUT|OUTPUT|WIRE) ID* -> decl
    assignment: LHS "=" expr -> assign

    ?expr: identifier | literal | call
    identifier: ID -> ident
    literal: LITERAL -> lit
    call: OP "(" (expr ("," expr)*)? ")" -> call_form

    // Lines to ignore/strip
    comment_line: "#" /[^\n]*/
    blank_line: /\s*/

    // Tokens
    LITERAL: "0" | "1" | "X"
    INPUT: "input"
    OUTPUT: "output"
    WIRE: "wire"
    OP: (NOT|BUF|AND|OR|XOR|NAND|NOR|XNOR)
    NOT: "NOT"
    BUF: "BUF"
    AND: "AND"
    OR: "OR"
    XOR: "XOR"
    NAND: "NAND"
    NOR: "NOR"
    XNOR: "XNOR"
    ID: /[_A-Za-z][_A-Za-z0-9]*/

    LHS: ID

    // Whitespace
    WHITESPACE: / [ \t]+/
    %ignore /\n/
"""


class CircTransformer(lark.Transformer):
    """Transform parse tree into structured data."""

    def __init__(self, filepath: str):
        super().__init__()
        self.filepath = filepath
        self.declarations: List[Tuple[str, List[str]]] = []  # (type, [names])
        self.assignments: List[Tuple[str, Tuple]] = []  # (lhs, (op, [args]))
        self.line_info: Dict[int, Tuple[str, int]] = {}  # line -> (type, col)
        self._line_count = 0

    def blank_line(self, _):
        return None

    def comment_line(self, _):
        return None

    def decl(self, items):
        decl_type = items[0].value.upper()  # INPUT, OUTPUT, WIRE
        names = [child.value for child in items[1:]]
        return (decl_type, names)

    def assign(self, items):
        lhs = items[0].value
        call = items[1]
        op = call[0].value.upper()
        args = [arg.value if hasattr(arg, 'value') else arg for arg in call[1:]]
        return (lhs, (op, args))

    def ident(self, items):
        return items[0].value

    def lit(self, items):
        val = items[0].value
        if val == 'X':
            raise CircParseError(
                "Literal X is forbidden",
                file=self.filepath,
                line=self._line_count,
                col=0
            )
        return val  # '0' or '1'

    def call_form(self, items):
        op = items[0]
        args = []
        for item in items[1:]:
            if isinstance(item, str):
                args.append(item)
            else:
                args.append(item)
        return (op, args)

    def line(self, items):
        result = []
        for item in items:
            if item is not None:
                result.append(item)
        return result if result else None

    def start(self, items):
        """Process all parsed lines."""
        all_lines = []
        for item in items:
            if item is not None:
                if isinstance(item, list):
                    for subitem in item:
                        if subitem is not None:
                            all_lines.append(subitem)
                elif item is not None:
                    all_lines.append(item)
        return all_lines


def parse_circ_file(filepath: str) -> Tuple[List[Tuple], List[Tuple]]:
    """Parse a .circ file and return (declarations, assignments)."""
    with open(filepath, 'r') as f:
        content = f.read()

    try:
        parser = lark.Lark(Circ_GRAMMAR, propagate_positions=True, parser='lalr')
        tree = parser.parse(content)
    except lark.exceptions.ParseError as e:
        # Try to extract line and column info
        line = e.line if hasattr(e, 'line') else None
        col = e.column if hasattr(e, 'column') else None
        raise CircParseError(
            f"Parse error: {str(e)}",
            file=filepath,
            line=line,
            col=col
        )

    transformer = CircTransformer(filepath)
    result = transformer.transform(tree)

    # Process the result
    declarations = []
    assignments = []
    seen_assignment = False

    for item in result:
        if isinstance(item, tuple) and len(item) == 2:
            if isinstance(item[1], list) and len(item[1]) > 0 and isinstance(item[1][0], str):
                # Declaration: (type, [names])
                if seen_assignment:
                    raise DeclarationAfterAssignmentError(
                        f"Declaration found after assignment",
                        file=filepath
                    )
                declarations.append(item)
            else:
                # Assignment: (lhs, (op, args))
                seen_assignment = True
                assignments.append(item)

    return declarations, assignments


def validate_circ_file(filepath: str, declarations: List[Tuple],
                       assignments: List[Tuple]) -> Dict[str, Any]:
    """Validate declarations and assignments."""

    # Track all declared signals
    inputs = set()
    outputs = set()
    wires = set()
    all_signals: Dict[str, str] = {}  # name -> type ('input', 'output', 'wire')

    # Operator arities
    op_arity = {
        'NOT': 1,
        'BUF': 1,
        'AND': 2,  # minimum
        'OR': 2,
        'XOR': 2,
        'NAND': 2,
        'NOR': 2,
        'XNOR': 2,
    }

    # Process declarations
    for decl_type, names in declarations:
        decl_type_lower = decl_type.lower()
        for name in names:
            if name in all_signals:
                raise DuplicateNameError(
                    f"Duplicate signal name: {name}",
                    file=filepath
                )
            all_signals[name] = decl_type_lower
            if decl_type_lower == 'input':
                inputs.add(name)
            elif decl_type_lower == 'output':
                outputs.add(name)
            elif decl_type_lower == 'wire':
                wires.add(name)

    # Track assignments
    assigned: Dict[str, Tuple[str, int]] = {}  # name -> (op, line_num)

    # Build dependency graph for cycle detection
    graph: Dict[str, List[str]] = {}
    all_assigned_names = set()

    for i, (lhs, (op, args)) in enumerate(assignments):
        line_num = i + 1  # approximate line number

        # Check LHS is valid
        if lhs not in all_signals:
            raise UndefinedNameError(
                f"Undefined signal: {lhs}",
                file=filepath
            )

        signal_type = all_signals[lhs]
        if signal_type == 'input':
            raise InputAssignmentError(
                f"Cannot assign to input: {lhs}",
                file=filepath
            )

        # Check for multiple assignment
        if lhs in assigned:
            raise MultipleAssignmentError(
                f"Multiple assignment to: {lhs}",
                file=filepath
            )

        assigned[lhs] = (op, line_num)
        all_assigned_names.add(lhs)

        # Check operand arity
        if op.lower() in op_arity:
            min_arity = op_arity[op.lower()]
            if len(args) < min_arity:
                raise ArityError(
                    f"Operator {op} requires at least {min_arity} operands, got {len(args)}",
                    file=filepath
                )
        else:
            raise ArityError(
                f"Unknown operator: {op}",
                file=filepath
            )

        # Check all operands are defined
        graph[lhs] = []
        for arg in args:
            if isinstance(arg, str):
                if arg not in all_signals:
                    raise UndefinedNameError(
                        f"Undefined signal: {arg}",
                        file=filepath
                    )
                graph[lhs].append(arg)
            elif arg == '0' or arg == '1':
                pass  # literals are fine
            else:
                raise UndefinedNameError(
                    f"Undefined signal",
                    file=filepath
                )

    # Check for unassigned signals (only wires and outputs)
    for name, sig_type in all_signals.items():
        if sig_type in ('wire', 'output'):
            if name not in assigned:
                raise UnassignedSignalError(
                    f"Unassigned signal: {name}",
                    file=filepath
                )

    # Check for cycles
    def find_cycle() -> Optional[List[str]]:
        """Find a cycle in the assignment graph."""
        visited = set()
        rec_stack = []
        path = {}

        def dfs(node):
            visited.add(node)
            rec_stack.append(node)

            for neighbor in graph.get(node, []):
                # Skip literals
                if neighbor in ('0', '1'):
                    continue
                if neighbor not in visited:
                    if neighbor in rec_stack:
                        # Found a cycle
                        start_idx = rec_stack.index(neighbor)
                        return rec_stack[start_idx:] + [node]
                    result = dfs(neighbor)
                    if result:
                        return result
                elif neighbor in rec_stack:
                    start_idx = rec_stack.index(neighbor)
                    return rec_stack[start_idx:] + [node]

            rec_stack.pop()
            return None

        for node in graph:
            if node not in visited:
                cycle = dfs(node)
                if cycle:
                    return cycle
        return None

    cycle = find_cycle()
    if cycle:
        cycle_path = " -> ".join(cycle)
        raise CycleError(
            f"Cycle detected: {cycle_path}",
            file=filepath
        )

    # Return success info
    sorted_inputs = sorted([{'name': n, 'msb': 0, 'lsb': 0} for n in sorted(inputs)])
    sorted_outputs = sorted([{'name': n, 'msb': 0, 'lsb': 0} for n in sorted(outputs)])

    return {
        'inputs': sorted_inputs,
        'outputs': sorted_outputs,
    }


