import argparse
from dataclasses import dataclass, field, asdict
from typing import Optional, List, Dict, Any, Tuple
from enum import Enum
import lark

VERSION = "0.1.0"

# =============================================================================
# Error Classes
# =============================================================================

class CircuitError(Exception):
    """Base error for circuit-related errors."""
    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message)
        self.message = message
        self.file = file
        self.line = line
        self.col = col


class CliUsageError(CircuitError):
    exit_code = 1


class FileNotFoundError(CircuitError):
    exit_code = 1

    def __init__(self, message: str, filepath: str):
        super().__init__(message, file=filepath)


class CircParseError(CircuitError):
    exit_code = 2


class DeclarationAfterAssignmentError(CircuitError):
    exit_code = 3


class DuplicateNameError(CircuitError):
    exit_code = 3


class UndefinedNameError(CircuitError):
    exit_code = 3


class UnassignedSignalError(CircuitError):
    exit_code = 3


class InputAssignmentError(CircuitError):
    exit_code = 3


class MultipleAssignmentError(CircuitError):
    exit_code = 3


class ArityError(CircuitError):
    exit_code = 3


class CycleError(CircuitError):
    exit_code = 3


# =============================================================================
# Parser using Lark
# =============================================================================

 Circ_GRAMMAR = r"""
    // Comments and whitespace handled by transformer
    ?start: line*

    // Declaration lines
    ?line: declaration | assignment | comment_line | blank_line

    declaration: (INPUT|OUTPUT|WIRE) ID* -> decl
    assignment: LHS "=" expr -> assign

    ?expr: identifier | literal | call
    identifier: ID -> ident
    literal: LITERAL -> lit
    call: OP "(" (expr ("," expr)*)? ")" -> call_form

    // Lines to ignore/strip
    comment_line: "#" /[^\n]*/
    blank_line: /\s*/

    // Tokens
    LITERAL: "0" | "1" | "X"
    INPUT: "input"
    OUTPUT: "output"
    WIRE: "wire"
    OP: (NOT|BUF|AND|OR|XOR|NAND|NOR|XNOR)
    NOT: "NOT"
    BUF: "BUF"
    AND: "AND"
    OR: "OR"
    XOR: "XOR"
    NAND: "NAND"
    NOR: "NOR"
    XNOR: "XNOR"
    ID: /[_A-Za-z][_A-Za-z0-9]*/

    LHS: ID

    // Whitespace
    WHITESPACE: / [ \t]+/
    %ignore /\n/
"""


class CircTransformer(lark.Transformer):
    """Transform parse tree into structured data."""

    def __init__(self, filepath: str):
        super().__init__()
        self.filepath = filepath
        self.declarations: List[Tuple[str, List[str]]] = []  # (type, [names])
        self.assignments: List[Tuple[str, Tuple]] = []  # (lhs, (op, [args]))
        self.line_info: Dict[int, Tuple[str, int]] = {}  # line -> (type, col)
        self._line_count = 0

    def blank_line(self, _):
        return None

    def comment_line(self, _):
        return None

    def decl(self, items):
        decl_type = items[0].value.upper()  # INPUT, OUTPUT, WIRE
        names = [child.value for child in items[1:]]
        return (decl_type, names)

    def assign(self, items):
        lhs = items[0].value
        call = items[1]
        op = call[0].value.upper()
        args = [arg.value if hasattr(arg, 'value') else arg for arg in call[1:]]
        return (lhs, (op, args))

    def ident(self, items):
        return items[0].value

    def lit(self, items):
        val = items[0].value
        if val == 'X':
            raise CircParseError(
                "Literal X is forbidden",
                file=self.filepath,
                line=self._line_count,
                col=0
            )
        return val  # '0' or '1'

    def call_form(self, items):
        op = items[0]
        args = []
        for item in items[1:]:
            if isinstance(item, str):
                args.append(item)
            else:
                args.append(item)
        return (op, args)

    def line(self, items):
        result = []
        for item in items:
            if item is not None:
                result.append(item)
        return result if result else None

    def start(self, items):
        """Process all parsed lines."""
        all_lines = []
        for item in items:
            if item is not None:
                if isinstance(item, list):
                    for subitem in item:
                        if subitem is not None:
                            all_lines.append(subitem)
                elif item is not None:
                    all_lines.append(item)
        return all_lines


def parse_circ_file(filepath: str) -> Tuple[List[Tuple], List[Tuple]]:
    """Parse a .circ file and return (declarations, assignments)."""
    with open(filepath, 'r') as f:
        content = f.read()

    try:
        parser = lark.Lark(Circ_GRAMMAR, propagate_positions=True, parser='lalr')
        tree = parser.parse(content)
    except lark.exceptions.ParseError as e:
        # Try to extract line and column info
        line = e.line if hasattr(e, 'line') else None
        col = e.column if hasattr(e, 'column') else None
        raise CircParseError(
            f"Parse error: {str(e)}",
            file=filepath,
            line=line,
            col=col
        )

    transformer = CircTransformer(filepath)
    result = transformer.transform(tree)

    # Process the result
    declarations = []
    assignments = []
    seen_assignment = False

    for item in result:
        if isinstance(item, tuple) and len(item) == 2:
            if isinstance(item[1], list) and len(item[1]) > 0 and isinstance(item[1][0], str):
                # Declaration: (type, [names])
                if seen_assignment:
                    raise DeclarationAfterAssignmentError(
                        f"Declaration found after assignment",
                        file=filepath
                    )
                declarations.append(item)
            else:
                # Assignment: (lhs, (op, args))
                seen_assignment = True
                assignments.append(item)

    return declarations, assignments


def validate_circ_file(filepath: str, declarations: List[Tuple],
