                line=self._line_count,
                col=0
            )
        return val  # '0' or '1'

    def call_form(self, items):
        op = items[0]
        args = []
        for item in items[1:]:
            if isinstance(item, str):
                args.append(item)
            else:
                args.append(item)
        return (op, args)

    def line(self, items):
        result = []
        for item in items:
            if item is not None:
                result.append(item)
        return result if result else None

    def start(self, items):
        """Process all parsed lines."""
        all_lines = []
        for item in items:
            if item is not None:
                if isinstance(item, list):
                    for subitem in item:
                        if subitem is not None:
                            all_lines.append(subitem)
                elif item is not None:
                    all_lines.append(item)
        return all_lines


def parse_circ_file(filepath: str) -> Tuple[List[Tuple], List[Tuple]]:
    """Parse a .circ file and return (declarations, assignments)."""
    with open(filepath, 'r') as f:
        content = f.read()

    try:
        parser = lark.Lark(_GRAMMAR, propagate_positions=True, parser='lalr')
        tree = parser.parse(content)
    except lark.exceptions.ParseError as e:
        # Try to extract line and column info
        line = e.line if hasattr(e, 'line') else None
        col = e.column if hasattr(e, 'column') else None
        raise CircParseError(
            f"Parse error: {str(e)}",
            file=filepath,
            line=line,
            col=col
        )

    transformer = CircTransformer(filepath)
    result = transformer.transform(tree)

    # Process the result
    declarations = []
    assignments = []
    seen_assignment = False

    for item in result:
        if isinstance(item, tuple) and len(item) == 2:
            if isinstance(item[1], list) and len(item[1]) > 0 and isinstance(item[1][0], str):
                # Declaration: (type, [names])
                if seen_assignment:
                    raise DeclarationAfterAssignmentError(
                        f"Declaration found after assignment",
                        file=filepath
                    )
                declarations.append(item)
            else:
                # Assignment: (lhs, (op, args))
                seen_assignment = True
                assignments.append(item)

    return declarations, assignments


def validate_circ_file(filepath: str, declarations: List[Tuple],
                       assignments: List[Tuple]) -> Dict[str, Any]:
    """Validate declarations and assignments."""

    # Track all declared signals
    inputs = set()
    outputs = set()
    wires = set()
    all_signals: Dict[str, str] = {}  # name -> type ('input', 'output', 'wire')

    # Operator arities
    op_arity = {
        'NOT': 1,
        'BUF': 1,
        'AND': 2,  # minimum
        'OR': 2,
        'XOR': 2,
        'NAND': 2,
        'NOR': 2,
        'XNOR': 2,
    }

    # Process declarations
    for decl_type, names in declarations:
        decl_type_lower = decl_type.lower()
        for name in names:
            if name in all_signals:
                raise DuplicateNameError(
                    f"Duplicate signal name: {name}",
                    file=filepath
                )
            all_signals[name] = decl_type_lower
            if decl_type_lower == 'input':
                inputs.add(name)
            elif decl_type_lower == 'output':
                outputs.add(name)
            elif decl_type_lower == 'wire':
                wires.add(name)

    # Track assignments
    assigned: Dict[str, Tuple[str, int]] = {}  # name -> (op, line_num)

    # Build dependency graph for cycle detection
    graph: Dict[str, List[str]] = {}
    all_assigned_names = set()

    for i, (lhs, (op, args)) in enumerate(assignments):
        line_num = i + 1  # approximate line number

        # Check LHS is valid
        if lhs not in all_signals:
            raise UndefinedNameError(
                f"Undefined signal: {lhs}",
                file=filepath
            )

        signal_type = all_signals[lhs]
        if signal_type == 'input':
            raise InputAssignmentError(
                f"Cannot assign to input: {lhs}",
                file=filepath
            )

        # Check for multiple assignment
        if lhs in assigned:
            raise MultipleAssignmentError(
                f"Multiple assignment to: {lhs}",
                file=filepath
            )

        assigned[lhs] = (op, line_num)
        all_assigned_names.add(lhs)

        # Check operand arity
        if op.lower() in op_arity:
            min_arity = op_arity[op.lower()]
            if len(args) < min_arity:
                raise ArityError(
                    f"Operator {op} requires at least {min_arity} operands, got {len(args)}",
                    file=filepath
                )
        else:
            raise ArityError(
                f"Unknown operator: {op}",
                file=filepath
            )

        # Check all operands are defined
        graph[lhs] = []
        for arg in args:
            if isinstance(arg, str):
                if arg not in all_signals:
                    raise UndefinedNameError(
                        f"Undefined signal: {arg}",
                        file=filepath
                    )
                graph[lhs].append(arg)
            elif arg == '0' or arg == '1':
                pass  # literals are fine
            else:
                raise UndefinedNameError(
                    f"Undefined signal",
                    file=filepath
                )

    # Check for unassigned signals (only wires and outputs)
    for name, sig_type in all_signals.items():
        if sig_type in ('wire', 'output'):
            if name not in assigned:
                raise UnassignedSignalError(
                    f"Unassigned signal: {name}",
                    file=filepath
                )

    # Check for cycles
    def find_cycle() -> Optional[List[str]]:
        """Find a cycle in the assignment graph."""
        visited = set()
        rec_stack = []
        path = {}

        def dfs(node):
            visited.add(node)
            rec_stack.append(node)

            for neighbor in graph.get(node, []):
                # Skip literals
                if neighbor in ('0', '1'):
                    continue
                if neighbor not in visited:
                    if neighbor in rec_stack:
                        # Found a cycle
                        start_idx = rec_stack.index(neighbor)
                        return rec_stack[start_idx:] + [node]
                    result = dfs(neighbor)
                    if result:
                        return result
                elif neighbor in rec_stack:
                    start_idx = rec_stack.index(neighbor)
                    return rec_stack[start_idx:] + [node]

            rec_stack.pop()
            return None

        for node in graph:
            if node not in visited:
                cycle = dfs(node)
                if cycle:
                    return cycle
        return None

    cycle = find_cycle()
    if cycle:
        cycle_path = " -> ".join(cycle)
        raise CycleError(
            f"Cycle detected: {cycle_path}",
            file=filepath
        )

    # Return success info
    sorted_inputs = sorted([{'name': n, 'msb': 0, 'lsb': 0} for n in sorted(inputs)])
    sorted_outputs = sorted([{'name': n, 'msb': 0, 'lsb': 0} for n in sorted(outputs)])

    return {
        'inputs': sorted_inputs,
        'outputs': sorted_outputs,
    }


# =============================================================================
# CLI
# =============================================================================

def format_error_json(error: CircuitError, command: str) -> str:
    """Format error as JSON envelope."""
    error_type = type(error).__name__
    result = {
        'ok': False,
        'command': command,
        'exit_code': error.exit_code,
        'error': {
            'type': error_type,
            'message': error.message,
            'file': error.file,
            'line': error.line,
            'col': error.col,
        }
    }
    return json.dumps(result)


def format_version_json() -> str:
    """Format version output as JSON."""
    return json.dumps({
        'ok': True,
        'command': '__version__',
        'version': VERSION,
    })


def cmd_check(filepath: str, json_output: bool) -> int:
    """Execute check command."""
    try:
        declarations, assignments = parse_circ_file(filepath)
        result = validate_circ_file(filepath, declarations, assignments)

        output = {
            'ok': True,
            'command': 'check',
            'format': 'circ',
            'inputs': result['inputs'],
            'outputs': result['outputs'],
        }

        if json_output:
            print(json.dumps(output))
        else:
            print(f"Inputs: {', '.join(i['name'] for i in result['inputs'])}")
            print(f"Outputs: {', '.join(o['name'] for o in result['outputs'])}")

        return 0

    except FileNotFoundError:
        if json_output:
            print(format_error_json(
                FileNotFoundError(f"File not found: {filepath}", filepath),
                'check'
            ))
        else:
            print(f"Error: File not found: {filepath}", file=sys.stderr)
        return 1

    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'check'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code


def main():
    parser = argparse.ArgumentParser(
        prog='circopt',
        description='Circuit optimizer',
        add_help=False,
    )
    parser.add_argument('--help', action='store_true', default=False)
    parser.add_argument('--version', action='store_true', default=False)
    parser.add_argument('--json', action='store_true', default=False)
    parser.add_argument('command', nargs='?', default=None)
    parser.add_argument('file', nargs='?', default=None)

    args = parser.parse_args()

    # Handle --help
    if args.help:
        if args.json:
            # Help is always plain text per spec
            pass
        print("Usage: circopt [OPTIONS] <COMMAND> [ARGS]")
        print("")
        print("Options:")
        print("  --help, -h      Show this help message")
        print("  --version, -v   Show version information")
        print("  --json          Output as JSON")
        print("")
        print("Commands:")
        print("  check <file>    Parse and validate a .circ file")
        return 0

    # Handle --version
    if args.version:
        if args.json:
            print(format_version_json())
        else:
            print(VERSION)
        return 0

    # No command provided (usage error)
    if args.command is None:
        if args.json:
            print(json.dumps({
                'ok': False,
                'command': '__cli__',
                'exit_code': 1,
                'error': {
                    'type': 'CliUsageError',
                    'message': 'No command specified',
                    'file': None,
                    'line': None,
                    'col': None,
                }
            }))
        else:
            print("Error: No command specified", file=sys.stderr)
            print("Use --help for usage information", file=sys.stderr)
        return 1

    # Handle commands
    if args.command == 'check':
        if args.file is None:
            if args.json:
                print(json.dumps({
                    'ok': False,
                    'command': 'check',
                    'exit_code': 1,
                    'error': {
                        'type': 'CliUsageError',
                        'message': 'Missing required argument: <file>',
                        'file': None,
                        'line': None,
                        'col': None,
                    }
                }))
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1
        return cmd_check(args.file, args.json)
    else:
        if args.json:
            print(json.dumps({
                'ok': False,
                'command': '__cli__',
                'exit_code': 1,
                'error': {
                    'type': 'CliUsageError',
                    'message': f"Unknown command: {args.command}",
                    'file': None,
                    'line': None,
                    'col': None,
                }
            }))
        else:
            print(f"Error: Unknown command: {args.command}", file=sys.stderr)
        return 1


if __name__ == '__main__':
    sys.exit(main())

